import{C as r,o as c,c as s,E as a,j as e,a as o,a5 as l,a6 as h,a2 as g}from"./chunks/framework.CkaEw-3u.js";const b=JSON.parse('{"title":"カメラ設定 (Camera Settings)","description":"3Dプリセット専用カメラの注視点、角度、遠近感、ズーム、レンズシフト","frontmatter":{"title":"カメラ設定 (Camera Settings)","description":"3Dプリセット専用カメラの注視点、角度、遠近感、ズーム、レンズシフト","pageClass":"reference-page"},"headers":[],"relativePath":"reference/reference-camera-settings.md","filePath":"reference/reference-camera-settings.md"}'),m={name:"reference/reference-camera-settings.md"},C=Object.assign(m,{setup(p){const i={camera:{image:"/image/inspector_camera_settings.webp",alt:"Camera Settings の Inspector",label:"Camera Settings",sourceWidth:613,sourceHeight:438,top:0,bottom:438}};return(f,t)=>{const d=r("ReferenceOverview"),n=r("InspectorCrop");return c(),s("div",null,[a(d,{eyebrow:"PARAMETER REFERENCE",title:"Camera Settings",description:"3Dタイポグラフィを見る位置と投影方法を制御します。注視点、カメラ角度、遠近感、ズーム、レンズシフトを目的から探せます。",items:[{icon:"◎",title:"Target",description:"カメラの注視点",href:"#パラメーター"},{icon:"↻",title:"Orbit",description:"Yaw・Pitchで回り込む",href:"#パラメーター"},{icon:"△",title:"Perspective",description:"遠近感の強さ",href:"#パラメーター"},{icon:"⌕",title:"Zoom",description:"投影サイズを調整",href:"#パラメーター"},{icon:"↔",title:"Lens Shift",description:"投影中心を平行移動",href:"#パラメーター"},{icon:"✥",title:"Viewer Control",description:"ビューアから直接操作",href:"#ビューアから操作する"}]}),t[0]||(t[0]=e("p",null,[e("code",null,"Mug Typography 3D"),o("と"),e("code",null,"Mug Typography Lite (3D)"),o("でのみ表示される、3D投影用のカメラ設定ページです。テキスト自体の向きはGlobal／Character Settingsで、テキストを見る位置と投影方法はこのページで調整します。")],-1)),a(n,l(h(i.camera)),null,16),t[1]||(t[1]=g('<h2 id="パラメーター" tabindex="-1">パラメーター <a class="header-anchor" href="#パラメーター" aria-label="Permalink to &quot;パラメーター&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメーター</th><th>説明</th><th style="text-align:right;">デフォルト</th></tr></thead><tbody><tr><td><strong>Target</strong></td><td>カメラが注視する位置です。Global Positionと同じ正規化座標を使い、<code>0.5, 0.5</code>がキャンバス中央です。</td><td style="text-align:right;"><code>0.5, 0.5</code></td></tr><tr><td><strong>Camera Yaw</strong></td><td>注視点の周囲を水平方向に回り込む角度です。正の値でカメラが右へ回ります。</td><td style="text-align:right;"><code>0°</code></td></tr><tr><td><strong>Camera Pitch</strong></td><td>注視点の周囲を垂直方向に回り込む角度です。正の値で上から見下ろします。</td><td style="text-align:right;"><code>0°</code></td></tr><tr><td><strong>Perspective Strength</strong></td><td>遠近感の強さです。大きいほど近距離・広角のような台形変形が強くなり、小さいほど望遠のように平坦になります。</td><td style="text-align:right;"><code>0.5</code></td></tr><tr><td><strong>Camera Zoom</strong></td><td>遠近感を維持したまま、投影されるテキストの大きさを変更します。</td><td style="text-align:right;"><code>1.0</code></td></tr><tr><td><strong>Lens Shift</strong></td><td>視点を回転させずに投影中心をX/Y方向へずらします。正のYは上方向です。</td><td style="text-align:right;"><code>0.0, 0.0</code></td></tr></tbody></table><h2 id="ビューアから操作する" tabindex="-1">ビューアから操作する <a class="header-anchor" href="#ビューアから操作する" aria-label="Permalink to &quot;ビューアから操作する&quot;">​</a></h2><p><strong>Selection Mode</strong>を<code>Camera</code>にすると、ビューア上に専用の操作ハンドルが表示されます。</p><table tabindex="0"><thead><tr><th>操作</th><th>変更する設定</th></tr></thead><tbody><tr><td>Orbitハンドルをドラッグ</td><td>Camera Yaw / Camera Pitch</td></tr><tr><td>空白部分を<code>Alt</code>ドラッグ（macOS: <code>Option</code>ドラッグ）</td><td>Camera Yaw / Camera Pitch</td></tr><tr><td>Target Padをドラッグ</td><td>Target</td></tr><tr><td>Zoomハンドルを左右へドラッグ</td><td>Camera Zoom</td></tr><tr><td>Perspectiveハンドルを左右へドラッグ</td><td>Perspective Strength</td></tr><tr><td>操作ハンドル以外の空白部分をドラッグ</td><td>Lens Shift</td></tr><tr><td>上記ドラッグ中に<code>Shift</code></td><td>移動量の大きい軸へ固定</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>Perspective Strength</strong>は遠近感だけを変え、見かけの大きさを保つよう設計されています。画面内のサイズ調整にはCamera Zoomを使い、Global Scaleはタイポグラフィ自体の大きさを変えたい場合に使います。</p></div><h2 id="カメラとオブジェクトの使い分け" tabindex="-1">カメラとオブジェクトの使い分け <a class="header-anchor" href="#カメラとオブジェクトの使い分け" aria-label="Permalink to &quot;カメラとオブジェクトの使い分け&quot;">​</a></h2><ul><li>テキスト全体をその場で傾ける: Global Yaw / Global Pitch</li><li>特定の文字だけを傾ける: Character Yaw / Pitch</li><li>文字やパーツを前後へ動かす: Z Offset</li><li>シーンを見る方向を変える: Camera Yaw / Pitch</li><li>構図だけを平行移動する: Lens Shift</li><li>遠近感を変える: Perspective Strength</li><li>画面内の大きさを変える: Camera Zoom</li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="/mug-typography-docs/features/feature-3d.html">3Dタイポグラフィを作る</a></li><li><a href="/mug-typography-docs/guide/interface.html#cameraモード-3dプリセット">インターフェース概要</a></li><li><a href="/mug-typography-docs/reference/reference-global-settings.html#_3dプリセット専用">Global Settings</a></li><li><a href="/mug-typography-docs/reference/reference-character-settings.html#_3dプリセットでの変形">Character Settings</a></li></ul>',10))])}}});export{b as __pageData,C as default};
